#nullable enable // autogenerated  

using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Contraptions;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;
using PVZEngine;
using PVZEngine.Entities;
using PVZEngine.Level;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [EntityBehaviourDefinition(VanillaContraptionNames.goldenDropper)]
    public class GoldenDropper : DispenserFamily
    {
        public GoldenDropper(string nsp, string name) : base(nsp, name)
        {
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            InitShootTimer(entity);
            SetTriggered(entity, false); // 初始化为未触发  
        }

        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);
            if (!entity.IsEvoked())
            {
                ShootTick(entity);
                return;
            }
        }

        public override bool CanTrigger(Entity entity)
        {
            // 已触发状态下无法再次触发  
            if (IsTriggered(entity))
                return false;
            return base.CanTrigger(entity);
        }

        protected override void OnTrigger(Entity entity)
        {
            base.OnTrigger(entity);
            SetTriggered(entity, true); // 触发后标记为已触发  
            entity.PlaySound(VanillaSoundID.launch);
        }

        public override Entity? Shoot(Entity entity)
        {
            var shotSpeed = entity.GetShotVelocity().magnitude;
            var isTriggered = IsTriggered(entity);

            if (isTriggered)
            {
                // 触发后：向三个方向发射  
                foreach (var direction in shootDirections)
                {
                    var dir = direction;
                    dir.x *= entity.GetFacingX();
                    var shootParams = entity.GetShootParams();
                    shootParams.velocity = dir * shotSpeed;
                    entity.ShootProjectile(shootParams);
                }
            }
            else
            {
                // 触发前：只发射一发（向前）  
                var dir = shootDirections[0];
                dir.x *= entity.GetFacingX();
                var shootParams = entity.GetShootParams();
                shootParams.velocity = dir * shotSpeed;
                return entity.ShootProjectile(shootParams);
            }

            return null;
        }

        protected override void OnEvoke(Entity entity)
        {
            base.OnEvoke(entity);
            var rng = entity.RNG;
            for (int i = 0; i < 30; i++)
            {
                var xspeed = entity.GetFacingX() * rng.Next(10f, 18f);
                var yspeed = rng.Next(30f);
                var zspeed = rng.Next(-1.5f, 1.5f);
                var param = entity.GetShootParams();
                param.velocity = new Vector3(xspeed, yspeed, zspeed);
                entity.ShootProjectile(param);
            }
            entity.PlaySound(VanillaSoundID.launch);
        }

        // 触发状态相关  
        public static bool IsTriggered(Entity entity) => entity.GetBehaviourField<bool>(ID, PROP_TRIGGERED);
        public static void SetTriggered(Entity entity, bool value) => entity.SetBehaviourField(ID, PROP_TRIGGERED, value);

        public static Vector3[] shootDirections = new Vector3[]
        {
            new Vector3(1, 0, 0),   // 向前  
            new Vector3(0.5f, 0, 0.25f).normalized,   // 向左上  
            new Vector3(0.5f, 0, -0.25f).normalized,    // 向右上  
        };

        private static readonly NamespaceID ID = VanillaContraptionID.goldenDropper;
        private static readonly VanillaEntityPropertyMeta<bool> PROP_TRIGGERED = new VanillaEntityPropertyMeta<bool>("Triggered");
    }
}